/**
 * BidChat — Sección del bloque Sala (Voyager DS)
 * Fuente: Figma VOYAGER · "BidChat" (panel 313×677)
 *
 * Panel de chat de puja (columna derecha): gradiente morado (#5F3ED8→#340091→
 * #140046), borde gradiente (white→naranja→lila→white) y sombra; esquinas
 * superiores rectas e inferiores redondeadas (16) tal cual el SVG.
 *
 * Contenido montado hasta ahora:
 *   · arriba (16px del top, centrado)   → BidProposal (propuesta · bid actual)
 *   · abajo  (16px del bottom, centrado) → BidButton
 *   · el centro (lista de mensajes) se montará después vía `children`.
 */

import type { JSX, ReactNode } from "react";
import BidProposal from "../../components/BidProposal/BidProposal";
import BidButton from "../../components/BidButton/BidButton";
import ChatArea from "./ChatArea";

export interface BidChatProps {
  className?: string;
  /** Contenido central (lista de mensajes, etc.) */
  children?: ReactNode;
}

export const BIDCHAT_WIDTH = 313;
export const BIDCHAT_HEIGHT = 677;

// Relleno morado: paint0 diagonal (#5F3ED8 → #340091 50% → #140046)
const FILL = "linear-gradient(115deg, #5F3ED8 0%, #340091 50%, #140046 100%)";
// Borde gradiente: paint1 (white → #F4AC59 → #8460E5 → white)
const BORDER = "linear-gradient(120deg, #ffffff 0%, #F4AC59 22%, #8460E5 74.5%, #ffffff 100%)";

export default function BidChat({ className = "", children }: BidChatProps): JSX.Element {
  return (
    <div
      className={className}
      data-block-section="bidchat"
      style={{
        boxSizing: "border-box",
        width: BIDCHAT_WIDTH,
        height: BIDCHAT_HEIGHT,
        // top recto, abajo redondeado 16 (tal cual el path del SVG)
        borderRadius: "0 0 16px 16px",
        backgroundImage: `${FILL}, ${BORDER}`,
        backgroundOrigin: "border-box",
        backgroundClip: "padding-box, border-box",
        border: "2px solid transparent",
        boxShadow: "rgba(0,0,0,0.35) 0px 0px 10px 4px",
        position: "relative",
        overflow: "hidden",
      }}
    >
      {/* Propuesta · bid actual · 16px del top, centrado */}
      <div style={{ position: "absolute", top: 16, left: 0, right: 0, display: "flex", justifyContent: "center" }}>
        <BidProposal />
      </div>

      {/* Área de mensajes 278×478 · 16px bajo la propuesta, centrada (con
          ProgressBar al fondo). El contenido de mensajes irá vía children. */}
      <div style={{ position: "absolute", top: 112, left: 0, right: 0, display: "flex", justifyContent: "center" }}>
        <ChatArea>{children}</ChatArea>
      </div>

      {/* Bid button · 16px del bottom, centrado */}
      <div style={{ position: "absolute", left: 0, right: 0, bottom: 16, display: "flex", justifyContent: "center" }}>
        <BidButton />
      </div>
    </div>
  );
}

/**
 * ChatArea — Sección del bloque Sala (Voyager DS)
 * Fuente: Figma VOYAGER · "Frame 1000022968" (área de mensajes 278×478)
 *
 * Fondo del área de mensajes del chat: morado translúcido (#5A35C2 40%),
 * radio 16 y borde superior sutil (white 0.1 → transparent). Por ahora es
 * solo el fondo; en el bottom va la ProgressBar (tiempo de bid) tal cual el
 * SVG. La lista de mensajes se montará encima vía `children`.
 */

import type { JSX, ReactNode } from "react";
import ProgressBar from "../../components/ProgressBar/ProgressBar";

export interface ChatAreaProps {
  /** Progreso de la barra inferior 0-100 (default 34, tal cual el SVG) */
  progress?: number;
  className?: string;
  /** Lista de mensajes (se monta encima del fondo) */
  children?: ReactNode;
}

export const CHATAREA_WIDTH = 278;
export const CHATAREA_HEIGHT = 478;

// Relleno morado translúcido (#5A35C2 @ 40%)
const FILL = "linear-gradient(rgba(90,53,194,0.4), rgba(90,53,194,0.4))";
// Borde: highlight blanco sutil arriba (paint13: white 0.1 → transparent)
const BORDER = "linear-gradient(180deg, rgba(255,255,255,0.1) 0%, rgba(255,255,255,0) 55%)";

export default function ChatArea({
  progress = 34,
  className = "",
  children,
}: ChatAreaProps): JSX.Element {
  return (
    <div
      className={className}
      data-block-section="chat-area"
      style={{
        boxSizing: "border-box",
        position: "relative",
        width: CHATAREA_WIDTH,
        height: CHATAREA_HEIGHT,
        borderRadius: 16,
        backgroundImage: `${FILL}, ${BORDER}`,
        backgroundOrigin: "border-box",
        backgroundClip: "padding-box, border-box",
        border: "1.5px solid transparent",
        overflow: "hidden",
      }}
    >
      {children}

      {/* ProgressBar (tiempo de bid) pegada al fondo, full-width */}
      <div style={{ position: "absolute", left: 0, right: 0, bottom: 0 }}>
        <ProgressBar value={progress} />
      </div>
    </div>
  );
}

"use client";

/**
 * ConsoleHeader — Sección del bloque Sala (Voyager DS)
 * Fuente: Figma VOYAGER · "ConsoleHeader" (2934:14478)
 *
 * Barra 991×64 (gradiente morado #5F3ED8→#140046, borde gradiente, sombra).
 * Izquierda: AvatarZone + "Mi C.U.U. ZAEX5G". Derecha: 4 columnas con divisores:
 *   · CONECTADOS  → PriceBadge + número
 *   · OFERTA      → BadgeStatus (live, editable, sin dot)
 *   · FONDOS      → texto
 *   · CONECTIVIDAD→ Signal
 * Compuesta con componentes Concorde.
 */

import type { JSX, ReactNode } from "react";
import AvatarZone from "../../components/AvatarZone/AvatarZone";
import PriceBadge from "../../components/PriceBadge/PriceBadge";
import BadgeStatus from "../../components/BadgeStatus/BadgeStatus";
import Signal from "../../components/Signal/Signal";

export const CONSOLEHEADER_WIDTH = 991;
export const CONSOLEHEADER_HEIGHT = 64;

export interface ConsoleHeaderProps {
  userLabel?: string;
  user?: string;
  conectados?: string;
  oferta?: string;
  fondos?: string;
  conectividad?: number;
  className?: string;
}

function StatCol({ label, children }: { label: string; children: ReactNode }): JSX.Element {
  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 6, padding: "0 18px", minWidth: 0 }}>
      <span style={{ fontSize: 9, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: "#ffffff", whiteSpace: "nowrap" }}>{label}</span>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: 22 }}>{children}</div>
    </div>
  );
}

function Divider(): JSX.Element {
  return <div style={{ width: 1, height: 44, background: "rgba(225,227,226,0.32)", flexShrink: 0 }} />;
}

export default function ConsoleHeader({
  userLabel = "Mi C.U.U.",
  user = "ZAEX5G",
  conectados = "18",
  oferta = "47292",
  fondos = "$100",
  conectividad = 4,
  className = "",
}: ConsoleHeaderProps): JSX.Element {
  return (
    <header
      className={className}
      style={{
        boxSizing: "border-box",
        width: CONSOLEHEADER_WIDTH,
        height: CONSOLEHEADER_HEIGHT,
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "0 16px",
        border: "1px solid transparent",
        backgroundImage:
          "linear-gradient(160deg, #5F3ED8 0%, #340091 50%, #140046 100%), linear-gradient(120deg, #ffffff 0%, #F4AC59 22%, #8460E5 74.5%, #ffffff 100%)",
        backgroundOrigin: "border-box",
        backgroundClip: "padding-box, border-box",
        boxShadow: "rgba(0,0,0,0.1) 0px 0px 16px 4px",
        fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
      }}
    >
      {/* Izquierda: avatar + usuario */}
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        <AvatarZone size={32} />
        <div style={{ display: "flex", alignItems: "baseline", gap: 6, color: "#ffffff", whiteSpace: "nowrap" }}>
          <span style={{ fontSize: 15, fontWeight: 500 }}>{userLabel}</span>
          <span style={{ fontSize: 16, fontWeight: 800, letterSpacing: "0.01em" }}>{user}</span>
        </div>
      </div>

      {/* Derecha: 4 columnas con divisores */}
      <div style={{ display: "flex", alignItems: "center" }}>
        <StatCol label="Conectados">
          <span style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <PriceBadge size={20} />
            <span style={{ fontSize: 16, fontWeight: 700, color: "#ffffff", fontVariantNumeric: "tabular-nums" }}>{conectados}</span>
          </span>
        </StatCol>
        <Divider />
        <StatCol label="Oferta">
          <BadgeStatus variant="live" label={oferta} icon={false} />
        </StatCol>
        <Divider />
        <StatCol label="Fondos">
          <span style={{ fontSize: 18, fontWeight: 800, color: "#ffffff", fontVariantNumeric: "tabular-nums", letterSpacing: "0.04em" }}>{fondos}</span>
        </StatCol>
        <Divider />
        <StatCol label="Conectividad">
          <Signal level={conectividad} width={30} />
        </StatCol>
      </div>
    </header>
  );
}

/**
 * PriceBase — Sección del bloque Sala (Voyager DS)
 * Fuente: Figma VOYAGER · "Background+Shadow" (card 272×106)
 *
 * Card "PRECIO BASE / US$ 5,000": fondo morado degradado, borde superior sutil
 * y sombra. Reusa el componente PriceIcon (la gema). Editable por props.
 */

import type { JSX } from "react";
import PriceIcon from "../../components/PriceIcon/PriceIcon";

export interface PriceBaseProps {
  /** Etiqueta superior (default "PRECIO BASE") */
  label?: string;
  /** Monto (default "US$ 5,000") */
  amount?: string;
  className?: string;
}

export const PRICEBASE_WIDTH = 272;
export const PRICEBASE_HEIGHT = 106;

// Relleno morado: paint0 horizontal (#19004A der → #2E0F70 izq)
const FILL = "linear-gradient(270deg, #19004A 0%, #3B1782 50%, #2E0F70 100%)";
// Borde: highlight blanco sutil arriba (paint1: white 0.1 → transparent)
const BORDER = "linear-gradient(180deg, rgba(255,255,255,0.12) 0%, rgba(255,255,255,0) 55%)";

export default function PriceBase({
  label = "PRECIO BASE",
  amount = "US$ 5,000",
  className = "",
}: PriceBaseProps): JSX.Element {
  return (
    <div
      className={className}
      data-slot="price-base"
      style={{
        boxSizing: "border-box",
        width: PRICEBASE_WIDTH,
        height: PRICEBASE_HEIGHT,
        borderRadius: 16,
        backgroundImage: `${FILL}, ${BORDER}`,
        backgroundOrigin: "border-box",
        backgroundClip: "padding-box, border-box",
        border: "1.5px solid transparent",
        boxShadow: "rgba(20,0,70,0.42) 0px 8px 22px, inset 0px 1px 0px rgba(255,255,255,0.2)",
        padding: "16px 20px",
        display: "flex",
        flexDirection: "column",
        justifyContent: "space-between",
        fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
      }}
    >
      <span
        style={{
          fontSize: 13,
          fontWeight: 700,
          letterSpacing: "0.06em",
          color: "#ffffff",
          textTransform: "uppercase",
        }}
      >
        {label}
      </span>
      <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
        <PriceIcon size="md" title="Precio base" />
        <span
          style={{
            fontSize: 30,
            fontWeight: 800,
            lineHeight: 1,
            color: "#ffffff",
            fontVariantNumeric: "tabular-nums",
          }}
        >
          {amount}
        </span>
      </div>
    </div>
  );
}

/**
 * Sala — Bloque de Concorde (Voyager DS)
 *
 * Sala de subasta. Por ahora es solo el lienzo base: un fondo de 1023 × 1042
 * con el color de marca (#2E0F70). Iremos montando las secciones encima.
 */

import type { JSX } from "react";
import ConsoleHeader from "./ConsoleHeader";
import PriceBase from "./PriceBase";
import StatPill from "./StatPill";
import BidChat from "./BidChat";
import SalaStatus from "../../components/SalaStatus/SalaStatus";
import CardViewer from "../../components/CardViewer/CardViewer";

export interface SalaProps {
  className?: string;
}

export const SALA_WIDTH = 1023;
export const SALA_HEIGHT = 1042;

const SALA_IMAGES = ["/demo/bronco.jpg", "/demo/bronco.jpg", "/demo/bronco.jpg", "/demo/bronco.jpg"];

export default function Sala({ className = "" }: SalaProps): JSX.Element {
  return (
    <div
      className={className}
      data-block="sala"
      style={{
        position: "relative",
        width: SALA_WIDTH,
        height: SALA_HEIGHT,
        background: "#2E0F70",
        overflow: "hidden",
      }}
    >
      {/* ConsoleHeader 991×64 · a 16px del top, centrado (16px a cada lado) */}
      <div style={{ position: "absolute", top: 16, left: 16 }}>
        <ConsoleHeader />
      </div>

      {/* Banner 204×930 · abajo-izquierda: 16px del left, 16px del bottom, 16px del header */}
      <div
        data-slot="left-banner"
        style={{
          position: "absolute",
          top: 96,
          left: 16,
          width: 204,
          height: 930,
          borderRadius: 8,
          background: "#E9EAEC",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          textAlign: "center",
          fontFamily: "monospace",
          fontSize: 12,
          letterSpacing: "0.08em",
          color: "#9AA1AC",
        }}
      >
        BANNER
        <br />
        204 × 930
      </div>

      {/* Columna derecha (443 ancho) · SalaStatus+visor (borde gradiente) ·
          filmstrip · y debajo la fila PRECIO BASE + pills */}
      <div
        style={{
          position: "absolute",
          top: 96,
          left: 236,
          width: 443,
          display: "flex",
          flexDirection: "column",
          gap: 16,
        }}
      >
        {/* El borde gradiente (slot header de CardViewer) envuelve SOLO
            SalaStatus + el visor; el filmstrip queda aparte, debajo. */}
        <CardViewer header={<SalaStatus />} images={SALA_IMAGES} />

        {/* Debajo del filmstrip · izquierda: PRECIO BASE (PriceIcon) ·
            derecha: 2 pills MIS BIDS / BIDS TOTALES (SendBidIcon) */}
        <div style={{ display: "flex", gap: 15, alignItems: "stretch" }}>
          <PriceBase />
          <div
            style={{
              flex: 1,
              display: "flex",
              flexDirection: "column",
              justifyContent: "space-between",
              gap: 12,
            }}
          >
            <StatPill variant="bids" label="MIS BIDS" value="18" />
            <StatPill variant="total" label="BIDS TOTALES" value="157" />
          </div>
        </div>

        {/* Banner inferior 443×237 · debajo de la fila PRECIO BASE + pills */}
        <div
          data-slot="bottom-banner"
          style={{
            width: 443,
            height: 237,
            borderRadius: 8,
            background: "#E9EAEC",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            textAlign: "center",
            fontFamily: "monospace",
            fontSize: 12,
            letterSpacing: "0.08em",
            color: "#9AA1AC",
          }}
        >
          BANNER
          <br />
          443 × 237
        </div>
      </div>

      {/* BidChat 313×677 · columna derecha, alineado al top del contenido.
          Por ahora solo el fondo + borde; el contenido se monta después. */}
      <div style={{ position: "absolute", top: 96, left: 694 }}>
        <BidChat />
      </div>
    </div>
  );
}

/**
 * StatPill — Sección del bloque Sala (Voyager DS)
 * Fuente: Figma VOYAGER · "Background+Shadow (1)/(2)" (pill 156×47)
 *
 * Pill de estadística con SendBidIcon a la izquierda + label/valor a la derecha.
 * 2 variantes:
 *   · "bids"  → naranja (MIS BIDS) · SendBidIcon "white" (flecha naranja)
 *   · "total" → morado  (BIDS TOTALES) · SendBidIcon "vault" (flecha blanca)
 * Reusa el componente SendBidIcon. Editable por props.
 */

import type { JSX } from "react";
import SendBidIcon from "../../components/SendBidIcon/SendBidIcon";

export type StatPillVariant = "bids" | "total";

export interface StatPillProps {
  /** Variante de color (default "bids") */
  variant?: StatPillVariant;
  /** Etiqueta (default "MIS BIDS") */
  label?: string;
  /** Valor (default "18") */
  value?: string;
  className?: string;
}

export const STATPILL_WIDTH = 156;
export const STATPILL_HEIGHT = 47;

// Naranja (MIS BIDS): paint0 vertical + borde gradiente vivo (white→naranja→lila→white)
const BIDS_FILL = "linear-gradient(180deg, #FF9639 0%, #EF852E 40%, #BE3D00 100%)";
const BIDS_BORDER = "linear-gradient(125deg, #ffffff 0%, #F4AC59 22%, #8460E5 74.5%, #ffffff 100%)";
// Morado (BIDS TOTALES): paint0 horizontal + highlight blanco sutil arriba
const TOTAL_FILL = "linear-gradient(270deg, #19004A 0%, #3B1782 50%, #2E0F70 100%)";
const TOTAL_BORDER = "linear-gradient(180deg, rgba(255,255,255,0.12) 0%, rgba(255,255,255,0) 55%)";

export default function StatPill({
  variant = "bids",
  label = "MIS BIDS",
  value = "18",
  className = "",
}: StatPillProps): JSX.Element {
  const isBids = variant === "bids";
  return (
    <div
      className={className}
      data-slot={`stat-pill-${variant}`}
      style={{
        boxSizing: "border-box",
        width: STATPILL_WIDTH,
        height: STATPILL_HEIGHT,
        borderRadius: 16,
        backgroundImage: isBids ? `${BIDS_FILL}, ${BIDS_BORDER}` : `${TOTAL_FILL}, ${TOTAL_BORDER}`,
        backgroundOrigin: "border-box",
        backgroundClip: "padding-box, border-box",
        border: "1.5px solid transparent",
        boxShadow: "rgba(20,0,70,0.42) 0px 8px 22px, inset 0px 1px 0px rgba(255,255,255,0.2)",
        display: "flex",
        alignItems: "center",
        gap: 14,
        padding: "0 12px 0 8px",
        fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
      }}
    >
      <SendBidIcon variant={isBids ? "white" : "vault"} size={32} aria-label="Enviar puja" />
      <span style={{ display: "flex", flexDirection: "column", gap: 1, minWidth: 0 }}>
        <span
          style={{
            fontSize: 11,
            fontWeight: 700,
            letterSpacing: "0.04em",
            lineHeight: 1,
            color: "#ffffff",
            textTransform: "uppercase",
            whiteSpace: "nowrap",
          }}
        >
          {label}
        </span>
        <span
          style={{
            fontSize: 20,
            fontWeight: 800,
            lineHeight: 1,
            color: "#ffffff",
            fontVariantNumeric: "tabular-nums",
          }}
        >
          {value}
        </span>
      </span>
    </div>
  );
}

"use client";

/**
 * BidProposal — Generado por Concorde
 * Fuente: Figma VOYAGER · "PropuestBid" (3162:13023)
 *
 * Card 280×80 (radio 14) con relleno gradiente morado (#5F3ED8 → #340091 →
 * #140046), borde gradiente (white → #F4AC59 → #8460E5 → white) y sombra. Arriba
 * un punto + label naranja con glow (#FF9C3B); debajo el monto grande blanco con
 * glow morado. `label` y `amount` editables. Copia del SVG (colores/efectos).
 */

import type { JSX } from "react";

export interface BidProposalProps {
  /** Texto superior (naranja) — default "PROPUESTA · BID ACTUAL" */
  label?: string;
  /** Monto grande (blanco) — default "US$ 25,000" */
  amount?: string;
  className?: string;
}

const STYLE_ID = "concorde-bidproposal-styles";

const BIDPROPOSAL_STYLES = `
.pbid {
  position: relative;
  box-sizing: border-box;
  width: 280px;
  max-width: 100%;
  height: 80px;
  border-radius: 14px;
  border: 2px solid transparent;
  background-image:
    linear-gradient(160deg, #5F3ED8 0%, #340091 50%, #140046 100%),
    linear-gradient(120deg, #ffffff 0%, #F4AC59 22%, #8460E5 74.5%, #ffffff 100%);
  background-origin: border-box;
  background-clip: padding-box, border-box;
  box-shadow: rgba(3,1,19,0.45) 0px 5px 20px, inset 0px 1px 0px rgba(255,255,255,0.16);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 4px;
  padding: 10px 16px;
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif);
  overflow: hidden;
}
.pbid__label {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.02em;
  text-transform: uppercase;
  color: #FF9C3B;
  text-shadow: 0 0 6px rgba(239,133,46,0.5);
  white-space: nowrap;
}
.pbid__dot {
  width: 5.3px;
  height: 5.3px;
  border-radius: 50%;
  background: #FF9C3B;
  box-shadow: 0 0 7px 1px rgba(239,133,46,0.9);
  flex-shrink: 0;
}
.pbid__amount {
  font-size: 34px;
  font-weight: 800;
  line-height: 1;
  letter-spacing: 0.01em;
  color: #ffffff;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
  text-shadow:
    0 0 4px rgba(174,166,255,0.7),
    0 0 9px rgba(107,85,222,0.6),
    0 0 18px rgba(82,52,189,0.5),
    0 0 30px rgba(49,0,138,0.4);
}
`;

let _stylesInjected = false;

export default function BidProposal({
  label = "PROPUESTA · BID ACTUAL",
  amount = "US$ 25,000",
  className = "",
}: BidProposalProps): JSX.Element {
  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = BIDPROPOSAL_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: BIDPROPOSAL_STYLES }} />
      <div className={`pbid ${className}`.trim()}>
        <span className="pbid__label">
          <span className="pbid__dot" aria-hidden="true" />
          {label}
        </span>
        <span className="pbid__amount">{amount}</span>
      </div>
    </>
  );
}

"use client";

/**
 * BidButton — Generado por Concorde
 * Fuente: Figma VOYAGER · "Button" (3182:12949)
 *
 * Pastilla (radio 27, alto 54) con relleno gradiente naranja→morado
 * (#ED8936 → #8460E5), borde gradiente (white → #F4AC59 → #8460E5 → white),
 * brillo superior y sombra. Dos textos (label + monto) separados por un divisor
 * vertical blanco 60%. `label` y `amount` editables. Copia del SVG.
 */

import type { JSX, MouseEventHandler } from "react";

export interface BidButtonProps {
  /** Texto izquierdo (default "BIDEAR") */
  label?: string;
  /** Monto derecho (default "US$ 25,000") */
  amount?: string;
